import React from "react";

function PopularSection() {
  let recipes = [
    {
      title: "Kremowy makaron z kurczakiem",
      category: "Obiad",
      image:
        "https://images.unsplash.com/photo-1621996346565-e3dbc646d9a9?auto=format&fit=crop&w=900&q=80"
    },
    {
      title: "Świeża sałatka warzywna",
      category: "Fit",
      image:
        "https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&w=900&q=80"
    },
    {
      title: "Pankejki z owocami",
      category: "Śniadanie",
      image:
        "https://images.unsplash.com/photo-1528207776546-365bb710ee93?auto=format&fit=crop&w=900&q=80"
    },
    {
      title: "Zupa krem z dyni",
      category: "Zupa",
      image:
        "https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=900&q=80"
    },
    {
      title: "Domowa lasagne",
      category: "Obiad",
      image:
        "https://images.unsplash.com/photo-1619895092538-128341789043?auto=format&fit=crop&w=900&q=80"
    },
    {
      title: "Sernik na zimno",
      category: "Deser",
      image:
        "https://images.unsplash.com/photo-1563729784474-d77dbb933a9e?auto=format&fit=crop&w=900&q=80"
    }
  ];

  return (
    <section className="section section-light">
      <div className="container">
        <div className="section-header">
          <h2>Popularne przepisy</h2>
          <p>Najchętniej oglądane i najciekawsze propozycje na naszej platformie.</p>
        </div>

        <div className="recipe-grid">
          {recipes.map((recipe, index) => (
            <div className="recipe-card" key={index}>
              <img src={recipe.image} alt={recipe.title} className="recipe-card-image" />
              <div className="recipe-card-body">
                <span className="recipe-badge">{recipe.category}</span>
                <h3>{recipe.title}</h3>
                <p>Poznaj składniki, sposób przygotowania i zapisz przepis do ulubionych.</p>
                <button className="secondary-button">Zobacz przepis</button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default PopularSection;
